import React from 'react'
import "./KarimField.scss"
import { ErrorMessage, useField, Field } from 'formik';
import { useTranslation } from 'react-i18next';

 type TKarimField = {
        name : string
        type : string 
        className? : string

} 
const KarimField = (
    {
        name,
        type,  
        className ,
        ...props
    }:TKarimField
) => {
    const [t] = useTranslation()
    const [meta] = useField({ name, ...props });


  return (
    <div className="KarimField">
  <label htmlFor="input" className="text">
    Name:
  </label>

  <Field
    type="text"
    placeholder="Write here..."
    name={name}
    className={`${meta.touched && meta.error ? `${className} is-invalid` : `${className}`}`}

  />
  <ErrorMessage name={name}>
          {(msg:any) => <span className="field-error text-danger">{t(msg)}</span>}
        </ErrorMessage>

</div>

  )
}

export default KarimField
